import type { CompletionContext } from '@codemirror/autocomplete';

import {
  usedPinnedFilters,
  usedRecentFilters,
} from '../../editor-state-configs/editor-config.js';
import type { FilterFieldSuggestion } from '../../suggestions/Suggestion.types.js';

export interface FilterFieldSuggestionRecentPinnedSuggestion {
  suggestion: FilterFieldSuggestion;
  position: number;
  ranges: Array<[number, number]>;
}

function mergeRanges(ranges: Array<[number, number]>): Array<[number, number]> {
  if (ranges.length === 0) {
    return [];
  }

  // Make sure the ranges are sorted by starting number
  ranges.sort((a, b) => a[0] - b[0]);

  const merged: Array<[number, number]> = [];

  let [start, end] = ranges[0];
  for (const [nextStart, nextEnd] of ranges) {
    if (nextStart <= end + 1) {
      // Overlap or touching ranges means the range can be extended
      end = Math.max(end, nextEnd);
    } else {
      // No overlapping ranges can be pushed directly.
      merged.push([start, end]);
      start = nextStart;
      end = nextEnd;
    }
  }
  merged.push([start, end]);

  return merged;
}

/**
 * Creates a regex matching pattern that allows optional white spaces around operator character
 * sequences and optional logical and operator string sequences.
 */
function createNeedleMatchPattern(needle: string): RegExp {
  // Ignore white spaces around comparison operators
  // Use the needle as a basis for the regex. For this, all restricted regex characters have to be escaped.
  const savePattern = needle
    .toLowerCase()
    .replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  // Create a operators map with placeholders and regex patterns. The placeholders
  // are necessary as longer operators need to be matched first and must have a
  // non matching placeholder for the remaining operators.
  // For example, matching != would still keep the = in there, which would match again,
  // adding optional white spaces between ! and =, which should not match.
  // This array also needs to be sorted by operator length to make sure the more explicit matches
  // are matched first.
  const operators = [
    { char: /\s*!=\s*\\\*/g, placeholder: 'ϴ0', pattern: '\\s*!=\\s*\\*' },
    { char: /\s*=\s*\\\*/g, placeholder: 'ϴ1', pattern: '\\s*=\\s*\\*' },
    { char: /\s*<=\s*/, placeholder: 'ϴ2', pattern: '\\s*<=\\s*' },
    { char: /\s*>=\s*/, placeholder: 'ϴ3', pattern: '\\s*>=\\s*' },
    { char: /\s*!=\s*/, placeholder: 'ϴ4', pattern: '\\s*!=\\s*' },
    { char: /\s*!~\s*/, placeholder: 'ϴ5', pattern: '\\s*!~\\s*' },
    { char: /\s*=\s*/, placeholder: 'ϴ6', pattern: '\\s*=\\s*' },
    { char: /\s*<\s*/, placeholder: 'ϴ7', pattern: '\\s*<\\s*' },
    { char: /\s*>\s*/, placeholder: 'ϴ8', pattern: '\\s*>\\s*' },
    { char: /\s*~\s*/, placeholder: 'ϴ9', pattern: '\\s*~\\s*' },
  ];

  const listOperator = [
    /*
     * Breakdown:
     * - (not )?         — optionally matches "not " before "in"
     * - in              — matches "in"
     * - \s*             — matches zero or more whitespace characters
     * - (?=\s*\\\()     — positive lookahead for an escaped "("
     * Purpose: Matches "in" or "not in", only if followed by an opening parenthesis.
     * https://regex101.com/r/qW9mOD/1
     */
    {
      char: /(\s*(not\s+)?in\s*)(?=\s*\\\()/g,
      placeholder: 'Ω0',
      pattern: '\\s*(not\\s+)?in\\s*',
    },
    /*
     * Breakdown:
     * - (?<=Ω0)         — positive lookbehind for the Ω0 placeholder ("in" or "not in")
     * - \\*\(           — an escaped "("
     * - \s*             — optional whitespace characters
     * Purpose: Matches an escaped opening parenthesis and optional whitespace after "in"/"not in".
     * https://regex101.com/r/ILgKSm/1
     */
    {
      char: /(?<=Ω0)\\*\(\s*/g,
      placeholder: 'Ω1',
      pattern: '\\(\\s*',
    },
    /*
     * Breakdown:
     * - (?<=Ω0[^)]*)    — positive lookbehind for Ω0 and any number of non-")" characters
     * - \s*             — optional whitespace characters
     * - \\*\)           — an escaped ")"
     * Purpose: Matches optional spaces and an escaped closing parenthesis at the end of the IN list.
     * https://regex101.com/r/pQTBe7/1
     */
    {
      char: /(?<=Ω0[^)]*)\s*\\*\)/g,
      placeholder: 'Ω2',
      pattern: '\\s*\\)*',
    },
    /*
     * Breakdown:
     * - \s*             — optional whitespace characters before the comma
     * - ,               — matches a literal comma
     * - \s*             — optional whitespace characters after the comma
     * - (?=.*Ω2)        — positive lookahead: ensures that closing parenthesis (Ω2) exists somewhere ahead in the string
     * Purpose: Matches commas with optional whitespace inside the IN list.
     * https://regex101.com/r/Yy86Vd/1
     */
    {
      char: /\s*,\s*(?=.*Ω2)/g,
      placeholder: 'Ω3',
      pattern: '\\s*,\\s*',
    },
  ];

  // In order to ignore the logical AND operators at any white space position
  // that is not around an operator, additional patterns are created that
  // make logical AND optional in the needle or haystack.
  const implicitLogicalAnd = [
    {
      // Regex for the logical AND matching can be lowercase as it only applies to an already lowercased string.
      char: /\sand\s/,
      placeholder: 'Φ0',
      /*
       * Breakdown:
       * - (?:...)   — non-capturing group with alternation
       * - |\s+      — OR: just one or more whitespace characters
       * - \s*AND\s+ — optional leading whitespace, then "AND", then required trailing whitespace
       *
       * This avoids nested quantifiers and handles whitespace before AND.
       * This pattern will match:
       * - " " (just whitespace)
       * - " AND " (whitespace before and after)
       * - "  AND  " (multiple spaces before and after)
       *
       * It will NOT match:
       * - "OR", "XOR", or any other logical operator
       *
       * Example matches:
       * - "foo = bar AND baz = qux"
       * - "foo = bar baz = qux"
       * - "foo = bar  AND  baz = qux"
       */
      pattern: '(?:\\s*AND\\s+|\\s+)',
    },
    { char: /\s+/g, placeholder: 'Φ1', pattern: '(?:\\s*AND\\s+|\\s+)' },
  ];

  const explicitGroup = [
    { char: /\\\(/g, placeholder: 'Φ4', pattern: '' },
    { char: /\\\)/g, placeholder: 'Φ5', pattern: '' },
    { char: /"/g, placeholder: 'Φ6', pattern: '' },
  ];

  let matchingPatterns = operators.concat(listOperator);
  matchingPatterns = matchingPatterns.concat(implicitLogicalAnd);
  matchingPatterns = matchingPatterns.concat(explicitGroup);

  let operatorOptionalWhitespacePattern = savePattern;
  // In the first pass we match all comparison or contains operators and replace them
  // with individual / non overlapping placeholders.
  for (const operator of matchingPatterns) {
    operatorOptionalWhitespacePattern =
      operatorOptionalWhitespacePattern.replace(
        new RegExp(operator.char, 'g'),
        operator.placeholder,
      );
  }

  // In the second pass we replace the placeholders with their respective pattern matching
  // making the white spaces in the right positions optional.
  for (const operator of matchingPatterns) {
    operatorOptionalWhitespacePattern =
      operatorOptionalWhitespacePattern.replace(
        new RegExp(operator.placeholder, 'g'),
        operator.pattern,
      );
  }

  // Create a regex from the constructed needle pattern with optional white spaces
  // around the operators
  return new RegExp(operatorOptionalWhitespacePattern, 'gi');
}

/**
 * Filtering logic for recent and pinned suggestions.
 * @internal
 */
export function fuzzySearchFilterSuggestion(
  haystack: FilterFieldSuggestion[],
  needle: string,
): Array<FilterFieldSuggestionRecentPinnedSuggestion> {
  const result: Array<FilterFieldSuggestionRecentPinnedSuggestion> = [];

  const lowercaseNeedle = needle.toLocaleLowerCase();
  const needleMatchPattern = createNeedleMatchPattern(lowercaseNeedle);

  for (const haystackItem of haystack) {
    const { value } = haystackItem;
    const lowercaseHaystackValue = value
      ?.toLocaleLowerCase()
      // Remove all brackets except those used in list operator,
      // as we want to match suggestions regardless of grouping.
      .replace(/(?<!\s(?:not\s)?in\s*)[()"]/g, '');

    // If the needle is empty, we have a match on all items.
    if (needleMatchPattern.source === '(?:)') {
      result.push({ suggestion: haystackItem, position: 0, ranges: [] });
      continue;
    }

    let match: FilterFieldSuggestionRecentPinnedSuggestion | null = null;
    if (lowercaseHaystackValue) {
      let fuzzyMatch;
      while (
        (fuzzyMatch = needleMatchPattern.exec(lowercaseHaystackValue)) !== null
      ) {
        // Initialize match object only once
        match ??= {
          suggestion: haystackItem,
          position: fuzzyMatch.index,
          ranges: [],
        };

        // Push the current match range
        match.ranges.push([
          fuzzyMatch.index,
          fuzzyMatch.index + fuzzyMatch[0].length,
        ]);
      }
    }

    // Attach the match to the actual result set.
    if (match !== null) {
      match.ranges = mergeRanges(match.ranges);
      result.push(match);
    }
  }

  return result;
}

/** @internal */
export function getRecentAndPinnedSuggestions(context: CompletionContext): {
  recentSuggestionValues: FilterFieldSuggestionRecentPinnedSuggestion[];
  pinnedSuggestionValues: FilterFieldSuggestionRecentPinnedSuggestion[];
} {
  // If we are on doc position 0, we can also add the saved filters from the
  // persisted state.
  const recentSuggestionValues: FilterFieldSuggestionRecentPinnedSuggestion[] =
    [];
  const pinnedSuggestionValues: FilterFieldSuggestionRecentPinnedSuggestion[] =
    [];

  // Extract the recent filters and trim them
  const recentFilters =
    context.view?.state.field<FilterFieldSuggestion[]>(usedRecentFilters);
  const currentFilterFieldInput = context.state.doc.toString().trim();

  if (recentFilters && Array.isArray(recentFilters)) {
    let filteredRecent = fuzzySearchFilterSuggestion(
      recentFilters,
      currentFilterFieldInput,
    );

    if (currentFilterFieldInput.length > 0) {
      // Show only 2 matching when filtered.
      filteredRecent = filteredRecent.slice(0, 2);
    } else {
      // Show at max 10 recent if not filtered.
      filteredRecent = filteredRecent.slice(0, 10);
    }

    recentSuggestionValues.push(...filteredRecent);
  }

  const pinnedFilters =
    context.view?.state.field<FilterFieldSuggestion[]>(usedPinnedFilters);
  if (pinnedFilters && Array.isArray(pinnedFilters)) {
    let filteredPinned = fuzzySearchFilterSuggestion(
      pinnedFilters,
      currentFilterFieldInput,
    );

    if (currentFilterFieldInput.length > 0) {
      // If the filter field has a current value, we filter down the recent filters for matches.
      filteredPinned = filteredPinned
        // Sort the ones with the lower match position first.
        .sort((filterA, filterB) => filterA.position - filterB.position);
    }
    pinnedSuggestionValues.push(...filteredPinned);
  }

  return { recentSuggestionValues, pinnedSuggestionValues };
}
